{
  "name": "GrowIQ - YouTube Intelligence",
  "description": "Automated YouTube growth dashboard featuring outlier detection, sentiment analysis, and strategic content recommendations."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  Video, 
  TrendingUp, 
  Lightbulb, 
  Image as ImageIcon, 
  Search, 
  Bell, 
  Menu,
  X
} from 'lucide-react';
import { DashboardHome } from './pages/DashboardHome';
import { MyChannel } from './pages/MyChannel';
import { OutlierExplorer } from './pages/OutlierExplorer';
import { Recommendations } from './pages/Recommendations';
import { SidebarItem } from './components/SidebarItem';

// Define view types
type View = 'dashboard' | 'my-channel' | 'outliers' | 'thumbnails' | 'recommendations';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Render the appropriate page based on currentView state
  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <DashboardHome onChangeView={setCurrentView} />;
      case 'my-channel':
        return <MyChannel />;
      case 'outliers':
        return <OutlierExplorer />;
      case 'recommendations':
        return <Recommendations />;
      default:
        return <DashboardHome onChangeView={setCurrentView} />;
    }
  };

  const toggleMobileMenu = () => setIsMobileMenuOpen(!isMobileMenuOpen);

  return (
    <div className="flex h-screen overflow-hidden bg-[#F4F7F6]">
      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar Navigation */}
      <aside 
        className={`
          fixed lg:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-100 transition-transform duration-300 ease-in-out
          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
        `}
      >
        <div className="flex flex-col h-full">
          {/* Logo */}
          <div className="flex items-center gap-3 px-8 py-8">
            <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-200">
              <TrendingUp className="text-white w-6 h-6" />
            </div>
            <span className="text-2xl font-bold text-gray-800 tracking-tight">GrowIQ</span>
          </div>

          {/* Navigation Links */}
          <nav className="flex-1 px-4 space-y-2 mt-4">
            <SidebarItem 
              icon={<LayoutDashboard size={20} />} 
              label="Dashboard" 
              isActive={currentView === 'dashboard'} 
              onClick={() => { setCurrentView('dashboard'); setIsMobileMenuOpen(false); }}
            />
            <SidebarItem 
              icon={<Video size={20} />} 
              label="My Channel" 
              isActive={currentView === 'my-channel'} 
              onClick={() => { setCurrentView('my-channel'); setIsMobileMenuOpen(false); }}
            />
            <SidebarItem 
              icon={<TrendingUp size={20} />} 
              label="Outlier Explorer" 
              isActive={currentView === 'outliers'} 
              onClick={() => { setCurrentView('outliers'); setIsMobileMenuOpen(false); }}
            />
            <SidebarItem 
              icon={<Lightbulb size={20} />} 
              label="Recommendations" 
              isActive={currentView === 'recommendations'} 
              onClick={() => { setCurrentView('recommendations'); setIsMobileMenuOpen(false); }}
            />
             <SidebarItem 
              icon={<ImageIcon size={20} />} 
              label="Thumbnail Lab" 
              isActive={currentView === 'thumbnails'} 
              onClick={() => { setCurrentView('thumbnails'); setIsMobileMenuOpen(false); }}
            />
          </nav>

          {/* User Profile Snippet */}
          <div className="p-4 border-t border-gray-100">
            <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-2xl">
              <img 
                src="https://picsum.photos/100/100" 
                alt="User" 
                className="w-10 h-10 rounded-full object-cover border-2 border-white shadow-sm"
              />
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-gray-900 truncate">Alex Creator</p>
                <p className="text-xs text-gray-500 truncate">alex@growiq.com</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-full w-full overflow-hidden">
        {/* Header */}
        <header className="h-20 flex items-center justify-between px-8 bg-[#F4F7F6] shrink-0">
          <div className="flex items-center gap-4">
            <button 
              onClick={toggleMobileMenu}
              className="p-2 bg-white rounded-xl shadow-sm lg:hidden hover:bg-gray-50 text-gray-600"
            >
              <Menu size={20} />
            </button>
            <h1 className="text-2xl font-bold text-gray-800 hidden md:block">
              {currentView === 'dashboard' && 'Growth Overview'}
              {currentView === 'my-channel' && 'Channel Analytics'}
              {currentView === 'outliers' && 'Market Intelligence'}
              {currentView === 'recommendations' && 'Strategy Center'}
              {currentView === 'thumbnails' && 'Thumbnail Lab'}
            </h1>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center bg-white px-4 py-2.5 rounded-2xl shadow-sm border border-gray-100 w-64">
              <Search size={18} className="text-gray-400 mr-2" />
              <input 
                type="text" 
                placeholder="Search topics..." 
                className="bg-transparent border-none outline-none text-sm text-gray-700 w-full placeholder-gray-400"
              />
            </div>
            <button className="p-2.5 bg-white rounded-xl shadow-sm border border-gray-100 relative hover:bg-gray-50 transition-colors">
              <Bell size={20} className="text-gray-600" />
              <span className="absolute top-2 right-2.5 w-2 h-2 bg-red-500 rounded-full ring-2 ring-white"></span>
            </button>
          </div>
        </header>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto px-4 md:px-8 pb-8">
          <div className="max-w-7xl mx-auto h-full">
            {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

// Performance Tiers
export type PerformanceTier = 'Elite' | 'Strong' | 'Average' | 'Weak';
export type TrendStatus = 'Rising' | 'Stable' | 'Declining';

// 3.1 Database Tables Representation
export interface Video {
  video_id: string;
  title: string;
  thumbnail_url: string;
  published_at: string;
  views: number;
  likes: number;
  comments_count: number;
  ctr: number;
  avg_view_duration: string;
  outlier_score: number;
  performance_tier: PerformanceTier;
}

export interface CompetitorVideo {
  video_id: string;
  channel_name: string;
  channel_avatar: string;
  title: string;
  thumbnail_url: string;
  published_at: string;
  views: number;
  view_velocity_48h: number; // views per hour in first 48h
  outlier_score: number;
  performance_tier: PerformanceTier;
  niche: string;
}

export interface Recommendation {
  recommendation_id: string;
  category: 'START' | 'STOP' | 'CONTINUE';
  title: string;
  description: string;
  confidence_score: number;
  supporting_data?: string;
}

export interface Trend {
  trend_id: string;
  topic_name: string;
  momentum_score: number;
  status: TrendStatus;
  video_count: number;
}

import React from 'react';

interface SidebarItemProps {
  icon: React.ReactNode;
  label: string;
  isActive: boolean;
  onClick: () => void;
}

export const SidebarItem: React.FC<SidebarItemProps> = ({ icon, label, isActive, onClick }) => {
  return (
    <button
      onClick={onClick}
      className={`
        w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl transition-all duration-200 group
        ${isActive 
          ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-200 font-medium' 
          : 'text-gray-500 hover:bg-emerald-50 hover:text-emerald-700'
        }
      `}
    >
      <div className={`${isActive ? 'opacity-100' : 'opacity-70 group-hover:opacity-100'}`}>
        {icon}
      </div>
      <span className="text-sm">{label}</span>

      {/* Active Indicator Dot */}
      {isActive && (
        <div className="ml-auto w-1.5 h-1.5 bg-white rounded-full opacity-80" />
      )}
    </button>
  );
};

import React from 'react';

interface DashboardCardProps {
  title?: string;
  subtitle?: string;
  children: React.ReactNode;
  className?: string;
  headerAction?: React.ReactNode;
}

export const DashboardCard: React.FC<DashboardCardProps> = ({ 
  title, 
  subtitle, 
  children, 
  className = '',
  headerAction
}) => {
  return (
    <div className={`bg-white rounded-[24px] p-6 shadow-sm border border-gray-100 flex flex-col ${className}`}>
      {(title || subtitle) && (
        <div className="flex items-start justify-between mb-6">
          <div>
            {title && <h3 className="text-lg font-bold text-gray-800 tracking-tight">{title}</h3>}
            {subtitle && <p className="text-sm text-gray-400 mt-1">{subtitle}</p>}
          </div>
          {headerAction && <div>{headerAction}</div>}
        </div>
      )}
      <div className="flex-1">
        {children}
      </div>
    </div>
  );
};

import React from 'react';
import { Play, TrendingUp, BarChart2 } from 'lucide-react';
import { Video, CompetitorVideo, PerformanceTier } from '../types';

interface VideoCardProps {
  video: Video | CompetitorVideo;
  isCompetitor?: boolean;
}

const getTierColor = (tier: PerformanceTier) => {
  switch (tier) {
    case 'Elite': return 'bg-amber-100 text-amber-700 border-amber-200';
    case 'Strong': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
    case 'Average': return 'bg-gray-100 text-gray-600 border-gray-200';
    case 'Weak': return 'bg-red-50 text-red-600 border-red-100';
    default: return 'bg-gray-100 text-gray-600';
  }
};

export const VideoCard: React.FC<VideoCardProps> = ({ video, isCompetitor = false }) => {
  return (
    <div className="group relative bg-white rounded-3xl overflow-hidden border border-gray-100 shadow-sm hover:shadow-md transition-all duration-300">
      {/* Thumbnail */}
      <div className="relative aspect-video overflow-hidden">
        <img 
          src={video.thumbnail_url} 
          alt={video.title} 
          className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-500" 
        />
        <div className="absolute inset-0 bg-black/10 group-hover:bg-black/0 transition-colors" />

        {/* Tier Badge */}
        <div className={`absolute top-3 left-3 px-3 py-1 rounded-full text-xs font-bold border ${getTierColor(video.performance_tier)} shadow-sm`}>
          {video.performance_tier === 'Elite' && '🔥 '}
          {video.performance_tier}
        </div>

        {/* Play Overlay */}
        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
          <div className="w-12 h-12 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg">
            <Play size={20} className="text-gray-900 fill-gray-900 ml-1" />
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="p-5">
        <div className="flex items-start justify-between gap-3 mb-2">
          {isCompetitor && 'channel_avatar' in video && (
             <img src={video.channel_avatar} alt="avatar" className="w-8 h-8 rounded-full border border-gray-200" />
          )}
          <h4 className="font-bold text-gray-800 text-sm leading-snug line-clamp-2 flex-1">
            {video.title}
          </h4>
        </div>

        {isCompetitor && 'channel_name' in video && (
            <p className="text-xs text-gray-500 mb-3 font-medium">{(video as CompetitorVideo).channel_name}</p>
        )}

        <div className="grid grid-cols-2 gap-2 mt-4">
          <div className="bg-gray-50 rounded-xl p-2.5">
            <div className="flex items-center gap-1.5 text-xs text-gray-400 mb-1">
              <TrendingUp size={12} />
              <span>Score</span>
            </div>
            <span className="text-lg font-bold text-gray-900">{video.outlier_score}x</span>
          </div>
          <div className="bg-gray-50 rounded-xl p-2.5">
            <div className="flex items-center gap-1.5 text-xs text-gray-400 mb-1">
              <BarChart2 size={12} />
              <span>Views</span>
            </div>
            <span className="text-lg font-bold text-gray-900">
              {(video.views / 1000).toFixed(1)}k
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

/**
 * This service would handle the Gemini API integrations described in the SOP.
 * Specifically for:
 * 2.3 SENTIMENT & COMMENT ANALYSIS
 * 2.8 START / STOP / CONTINUE RECOMMENDATIONS
 */

// NOTE: Since we cannot use a real API key in this generated artifact without user input,
// we will mock the "generation" delay and return structured data as if it came from the model.

import { Recommendation } from '../types';

export const generateStrategicInsights = async (): Promise<Recommendation[]> => {
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // In a real app, this would use:
    // const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // const response = await ai.models.generateContent({ model: 'gemini-3-pro-preview', contents: "..." })

    return [
        {
            recommendation_id: `gen-${Date.now()}-1`,
            category: 'START',
            title: 'AI Agent "Build-Along" Series',
            description: 'Sentiment analysis of competitor comments shows users are frustrated with "theoretical" videos. They want step-by-step code.',
            confidence_score: 94,
            supporting_data: '78% positive sentiment on "tutorial" keywords vs 45% on "news"'
        },
        {
            recommendation_id: `gen-${Date.now()}-2`,
            category: 'STOP',
            title: 'General AI News Recaps',
            description: 'The market is oversaturated. Your view velocity on news content is 40% lower than your evergreen tutorials.',
            confidence_score: 89,
            supporting_data: 'Saturation Index: High (8.9/10)'
        }
    ];
};

export const analyzeSentiment = async (videoId: string) => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    return {
        summary: "Viewers are highly engaged but confused about the installation process.",
        themes: ["Installation Issues", "Python Version Conflicts", "Appreciation for Clarity"],
        sentiment_score: 0.75 // 75% positive
    };
};

import React, { useState } from 'react';
import { OUTLIER_VIDEOS } from '../constants';
import { VideoCard } from '../components/VideoCard';
import { Filter, Search } from 'lucide-react';

const niches = ['All Niches', 'AI Automations', 'No-Code Tools', 'Productivity', 'Technology', 'AI News'];

export const OutlierExplorer: React.FC = () => {
    const [selectedNiche, setSelectedNiche] = useState('All Niches');

    const filteredVideos = selectedNiche === 'All Niches' 
        ? OUTLIER_VIDEOS 
        : OUTLIER_VIDEOS.filter(v => v.niche === selectedNiche);

    return (
        <div className="pb-12">
            {/* Header Controls */}
            <div className="mb-8">
                <h2 className="text-3xl font-bold text-gray-800 mb-2">Outlier Explorer</h2>
                <p className="text-gray-500 mb-6">Discover viral videos from your competitors before they peak.</p>

                <div className="flex flex-col md:flex-row gap-4 justify-between">
                    <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                        {niches.map(niche => (
                            <button
                                key={niche}
                                onClick={() => setSelectedNiche(niche)}
                                className={`
                                    whitespace-nowrap px-4 py-2 rounded-xl text-sm font-semibold transition-all border
                                    ${selectedNiche === niche 
                                        ? 'bg-gray-900 text-white border-gray-900 shadow-md' 
                                        : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                                    }
                                `}
                            >
                                {niche}
                            </button>
                        ))}
                    </div>
                    <div className="flex gap-2">
                        <button className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 rounded-xl text-sm font-medium text-gray-600 hover:bg-gray-50">
                            <Filter size={16} /> Filters
                        </button>
                    </div>
                </div>
            </div>

            {/* Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredVideos.map((video) => (
                    <VideoCard key={video.video_id} video={video} isCompetitor />
                ))}
            </div>

            {filteredVideos.length === 0 && (
                <div className="text-center py-20 text-gray-400">
                    <Search size={48} className="mx-auto mb-4 opacity-20" />
                    <p>No outliers found for this niche recently.</p>
                </div>
            )}
        </div>
    );
};

import React, { useState } from 'react';
import { RECOMMENDATIONS } from '../constants';
import { Recommendation } from '../types';
import { PlayCircle, StopCircle, RefreshCw, Wand2, Check } from 'lucide-react';
import { generateStrategicInsights } from '../services/geminiService';
import { DashboardCard } from '../components/DashboardCard';

export const Recommendations: React.FC = () => {
    const [items, setItems] = useState<Recommendation[]>(RECOMMENDATIONS);
    const [isGenerating, setIsGenerating] = useState(false);

    const handleGenerate = async () => {
        setIsGenerating(true);
        try {
            const newInsights = await generateStrategicInsights();
            // Append new insights to top
            setItems(prev => [...newInsights, ...prev]);
        } finally {
            setIsGenerating(false);
        }
    };

    const markActioned = (id: string) => {
        // In a real app, this would update Supabase
        setItems(prev => prev.filter(p => p.recommendation_id !== id));
    };

    const getColumnContent = (category: 'START' | 'STOP' | 'CONTINUE') => {
        return items.filter(i => i.category === category);
    };

    return (
        <div className="pb-12 h-full flex flex-col">
             <div className="flex justify-between items-start mb-8 shrink-0">
                <div>
                    <h2 className="text-3xl font-bold text-gray-800 mb-2">Strategic AI Recommendations</h2>
                    <p className="text-gray-500">Data-backed suggestions to optimize your content strategy.</p>
                </div>
                <button 
                    onClick={handleGenerate}
                    disabled={isGenerating}
                    className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-3 rounded-2xl font-bold shadow-lg shadow-emerald-200 transition-all disabled:opacity-70"
                >
                    {isGenerating ? (
                        <RefreshCw size={20} className="animate-spin" />
                    ) : (
                        <Wand2 size={20} />
                    )}
                    {isGenerating ? 'Analyzing Market...' : 'Generate New Insights'}
                </button>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1">
                {/* START Column */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2 px-1 mb-2">
                        <PlayCircle className="text-emerald-500" />
                        <h3 className="font-bold text-gray-700 uppercase tracking-wide">Start</h3>
                    </div>
                    {getColumnContent('START').map(rec => (
                        <RecommendationCard key={rec.recommendation_id} rec={rec} onAction={markActioned} colorClass="bg-emerald-50 border-emerald-100" />
                    ))}
                    {getColumnContent('START').length === 0 && <EmptyState text="No new opportunities detected." />}
                </div>

                {/* STOP Column */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2 px-1 mb-2">
                         <StopCircle className="text-red-500" />
                        <h3 className="font-bold text-gray-700 uppercase tracking-wide">Stop</h3>
                    </div>
                    {getColumnContent('STOP').map(rec => (
                        <RecommendationCard key={rec.recommendation_id} rec={rec} onAction={markActioned} colorClass="bg-red-50 border-red-100" />
                    ))}
                     {getColumnContent('STOP').length === 0 && <EmptyState text="No warnings at this time." />}
                </div>

                {/* CONTINUE Column */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2 px-1 mb-2">
                         <RefreshCw className="text-blue-500" />
                        <h3 className="font-bold text-gray-700 uppercase tracking-wide">Continue</h3>
                    </div>
                     {getColumnContent('CONTINUE').map(rec => (
                        <RecommendationCard key={rec.recommendation_id} rec={rec} onAction={markActioned} colorClass="bg-blue-50 border-blue-100" />
                    ))}
                     {getColumnContent('CONTINUE').length === 0 && <EmptyState text="Keep doing what you're doing." />}
                </div>
             </div>
        </div>
    );
};

const RecommendationCard = ({ rec, onAction, colorClass }: { rec: Recommendation, onAction: (id: string) => void, colorClass: string }) => (
    <div className={`p-6 rounded-[24px] border shadow-sm relative group bg-white hover:shadow-md transition-all`}>
        <div className={`absolute top-0 left-0 w-full h-1.5 ${rec.category === 'START' ? 'bg-emerald-500' : rec.category === 'STOP' ? 'bg-red-500' : 'bg-blue-500'} rounded-t-[24px]`}></div>

        <div className="flex justify-between items-start mb-3 mt-2">
            <h4 className="font-bold text-gray-900 text-lg leading-tight">{rec.title}</h4>
            <div className={`text-xs font-bold px-2 py-1 rounded-lg ${colorClass}`}>
                {rec.confidence_score}% Conf.
            </div>
        </div>

        <p className="text-gray-600 text-sm mb-4 leading-relaxed">
            {rec.description}
        </p>

        {rec.supporting_data && (
            <div className="bg-gray-50 rounded-xl p-3 mb-4 border border-gray-100">
                <p className="text-xs text-gray-500 font-semibold uppercase mb-1">Data Signal</p>
                <p className="text-xs text-gray-700 font-mono">{rec.supporting_data}</p>
            </div>
        )}

        <button 
            onClick={() => onAction(rec.recommendation_id)}
            className="w-full py-2.5 rounded-xl border border-gray-200 text-gray-500 text-sm font-semibold hover:bg-gray-50 hover:text-emerald-600 transition-colors flex items-center justify-center gap-2"
        >
            <Check size={16} /> Mark as Actioned
        </button>
    </div>
);

const EmptyState = ({ text }: { text: string }) => (
    <div className="p-8 border-2 border-dashed border-gray-200 rounded-[24px] flex items-center justify-center text-center">
        <p className="text-gray-400 text-sm font-medium">{text}</p>
    </div>
);

