                    <h2 className="text-3xl font-bold text-gray-800 mb-2">Strategic AI Recommendations</h2>
                    <p className="text-gray-500">Data-backed suggestions to optimize your content strategy.</p>
                </div>
                <button 
                    onClick={handleGenerate}
                    disabled={isGenerating}
                    className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-3 rounded-2xl font-bold shadow-lg shadow-emerald-200 transition-all disabled:opacity-70"
                >
                    {isGenerating ? (
                        <RefreshCw size={20} className="animate-spin" />
                    ) : (
                        <Wand2 size={20} />
                    )}
                    {isGenerating ? 'Analyzing Market...' : 'Generate New Insights'}
                </button>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1">
                {/* START Column */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2 px-1 mb-2">
                        <PlayCircle className="text-emerald-500" />
                        <h3 className="font-bold text-gray-700 uppercase tracking-wide">Start</h3>
                    </div>
                    {getColumnContent('START').map(rec => (
                        <RecommendationCard key={rec.recommendation_id} rec={rec} onAction={markActioned} colorClass="bg-emerald-50 border-emerald-100" />
                    ))}
                    {getColumnContent('START').length === 0 && <EmptyState text="No new opportunities detected." />}
                </div>

                {/* STOP Column */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2 px-1 mb-2">
                         <StopCircle className="text-red-500" />
                        <h3 className="font-bold text-gray-700 uppercase tracking-wide">Stop</h3>
                    </div>
                    {getColumnContent('STOP').map(rec => (
                        <RecommendationCard key={rec.recommendation_id} rec={rec} onAction={markActioned} colorClass="bg-red-50 border-red-100" />
                    ))}
                     {getColumnContent('STOP').length === 0 && <EmptyState text="No warnings at this time." />}
                </div>

                {/* CONTINUE Column */}
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2 px-1 mb-2">
                         <RefreshCw className="text-blue-500" />
                        <h3 className="font-bold text-gray-700 uppercase tracking-wide">Continue</h3>
                    </div>
                     {getColumnContent('CONTINUE').map(rec => (
                        <RecommendationCard key={rec.recommendation_id} rec={rec} onAction={markActioned} colorClass="bg-blue-50 border-blue-100" />
                    ))}
                     {getColumnContent('CONTINUE').length === 0 && <EmptyState text="Keep doing what you're doing." />}
                </div>
             </div>
        </div>
    );
};

interface RecommendationCardProps {
    rec: Recommendation;
    onAction: (id: string) => void;
    colorClass: string;
}

const RecommendationCard: React.FC<RecommendationCardProps> = ({ rec, onAction, colorClass }) => (
    <div className={`p-6 rounded-[24px] border shadow-sm relative group bg-white hover:shadow-md transition-all`}>
        <div className={`absolute top-0 left-0 w-full h-1.5 ${rec.category === 'START' ? 'bg-emerald-500' : rec.category === 'STOP' ? 'bg-red-500' : 'bg-blue-500'} rounded-t-[24px]`}></div>

        <div className="flex justify-between items-start mb-3 mt-2">
            <h4 className="font-bold text-gray-900 text-lg leading-tight">{rec.title}</h4>
            <div className={`text-xs font-bold px-2 py-1 rounded-lg ${colorClass}`}>
                {rec.confidence_score}% Conf.
            </div>
        </div>

        <p className="text-gray-600 text-sm mb-4 leading-relaxed">
            {rec.description}
        </p>

        {rec.supporting_data && (
            <div className="bg-gray-50 rounded-xl p-3 mb-4 border border-gray-100">
                <p className="text-xs text-gray-500 font-semibold uppercase mb-1">Data Signal</p>
                <p className="text-xs text-gray-700 font-mono">{rec.supporting_data}</p>
            </div>
        )}

        <button 
            onClick={() => onAction(rec.recommendation_id)}
            className="w-full py-2.5 rounded-xl border border-gray-200 text-gray-500 text-sm font-semibold hover:bg-gray-50 hover:text-emerald-600 transition-colors flex items-center justify-center gap-2"
        >
            <Check size={16} /> Mark as Actioned
        </button>
    </div>
);

const EmptyState = ({ text }: { text: string }) => (
    <div className="p-8 border-2 border-dashed border-gray-200 rounded-[24px] flex items-center justify-center text-center">
        <p className="text-gray-400 text-sm font-medium">{text}</p>
    </div>
);

// Performance Tiers
export type PerformanceTier = 'Elite' | 'Strong' | 'Average' | 'Weak';
export type TrendStatus = 'Rising' | 'Stable' | 'Declining';
export type IdeaStatus = 'Backlog' | 'Scripting' | 'Filming' | 'Editing' | 'Published';

// 3.1 Database Tables Representation
export interface Video {
  video_id: string;
  title: string;
  thumbnail_url: string;
  published_at: string;
  views: number;
  likes: number;
  comments_count: number;
  ctr: number;
  avg_view_duration: string;
  outlier_score: number;
  performance_tier: PerformanceTier;
  channel_name?: string;
}

export interface CompetitorVideo {
  video_id: string;
  channel_name: string;
  channel_avatar: string;
  title: string;
  thumbnail_url: string;
  published_at: string;
  views: number;
  view_velocity_48h: number; // views per hour in first 48h
  outlier_score: number;
  performance_tier: PerformanceTier;
  niche: string;
}

export interface Recommendation {
  recommendation_id: string;
  category: 'START' | 'STOP' | 'CONTINUE';
  title: string;
  description: string;
  confidence_score: number;
  supporting_data?: string;
}

export interface Trend {
  trend_id: string;
  topic_name: string;
  momentum_score: number;
  status: TrendStatus;
  video_count: number;
}

export interface Idea {
  idea_id: string;
  title: string;
  status: IdeaStatus;
  score: number;
  thumbnail_url?: string;
  notes?: string;
  source_url?: string;
}

import React, { useState } from 'react';
import { X, Search, Loader2, Save, TrendingUp } from 'lucide-react';
import { CHANNEL_AVG_VIEWS } from '../constants';
import { Idea } from '../types';

interface AddIdeaModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (idea: Idea) => void;
}

export const AddIdeaModal: React.FC<AddIdeaModalProps> = ({ isOpen, onClose, onSave }) => {
  const [url, setUrl] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [analyzedVideo, setAnalyzedVideo] = useState<any>(null);

  const handleAnalyze = async () => {
    if (!url) return;
    setIsLoading(true);

    // Simulate API fetch delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Mock Result
    const mockViews = Math.floor(Math.random() * 50000) + 5000;
    const outlierScore = (mockViews / CHANNEL_AVG_VIEWS).toFixed(1);

    setAnalyzedVideo({
      title: "Simulated Video Title from URL",
      thumbnail_url: `https://picsum.photos/seed/${Math.random()}/640/360`,
      views: mockViews,
      outlierScore: outlierScore
    });

    setIsLoading(false);
  };

  const handleSave = () => {
    if (analyzedVideo) {
      onSave({
        idea_id: `new-${Date.now()}`,
        title: analyzedVideo.title,
        status: 'Backlog',
        score: parseFloat(analyzedVideo.outlierScore),
        thumbnail_url: analyzedVideo.thumbnail_url,
        source_url: url
      });
      onClose();
      setUrl('');
      setAnalyzedVideo(null);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-3xl w-full max-w-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">

        {/* Header */}
        <div className="px-8 py-6 border-b border-gray-100 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold text-gray-800">Add New Idea</h2>
            <p className="text-gray-500 text-sm">Paste a YouTube URL to analyze its outlier potential.</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
            <X size={24} className="text-gray-400" />
          </button>
        </div>

        {/* Body */}
        <div className="p-8 space-y-8">

          {/* Input Section */}
          <div className="flex gap-4">
            <div className="flex-1 relative">
              <input 
                type="text" 
                placeholder="https://youtube.com/watch?v=..." 
                className="w-full pl-4 pr-12 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-gray-800 placeholder-gray-400"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAnalyze()}
              />
              <div className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400">
                <Search size={20} />
              </div>
            </div>
            <button 
              onClick={handleAnalyze}
              disabled={isLoading || !url}
              className="bg-gray-900 text-white px-8 py-4 rounded-xl font-bold hover:bg-gray-800 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
              {isLoading ? <Loader2 className="animate-spin" /> : 'Analyze'}
            </button>
          </div>

          {/* Result Section */}
          {analyzedVideo && (
            <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100 animate-in slide-in-from-bottom-4 duration-300">
              <div className="flex gap-6">
                <img 
                  src={analyzedVideo.thumbnail_url} 
                  alt="Thumbnail" 
                  className="w-48 aspect-video rounded-lg object-cover shadow-sm"
                />
                <div className="flex-1 space-y-2">
                  <h3 className="font-bold text-lg text-gray-900 leading-tight">{analyzedVideo.title}</h3>
                  <div className="flex items-center gap-4 text-sm text-gray-500">
                    <span>{analyzedVideo.views.toLocaleString()} views</span>
                    <span>•</span>
                    <span>Baseline: {CHANNEL_AVG_VIEWS.toLocaleString()} views</span>
                  </div>

                  {/* Outlier Visual */}
                  <div className="mt-4 pt-4 border-t border-gray-200/50 flex items-center justify-between">
                    <div className="flex flex-col">
                        <span className="text-xs font-bold uppercase text-gray-400 tracking-wider">Outlier Score</span>
                        <div className="flex items-baseline gap-1">
                            <span className={`text-3xl font-black ${
                                parseFloat(analyzedVideo.outlierScore) > 2 ? 'text-emerald-600' : 
                                parseFloat(analyzedVideo.outlierScore) > 1 ? 'text-amber-500' : 'text-gray-400'
                            }`}>
                                {analyzedVideo.outlierScore}x
                            </span>
                            <span className="text-sm font-medium text-gray-400">vs Avg</span>
                        </div>
                    </div>

                    {parseFloat(analyzedVideo.outlierScore) > 2 && (
                        <div className="bg-emerald-100 text-emerald-700 px-3 py-1.5 rounded-lg text-sm font-bold flex items-center gap-2">
                            <TrendingUp size={16} /> Viral Potential
                        </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-8 py-6 bg-gray-50 border-t border-gray-100 flex justify-end gap-3">
          <button onClick={onClose} className="px-6 py-3 font-semibold text-gray-600 hover:text-gray-900 hover:bg-gray-200/50 rounded-xl transition-colors">
            Cancel
          </button>
          <button 
            onClick={handleSave}
            disabled={!analyzedVideo}
            className="px-8 py-3 bg-emerald-600 text-white font-bold rounded-xl hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-200 disabled:opacity-50 disabled:shadow-none flex items-center gap-2"
          >
            <Save size={18} />
            Save to Queue
          </button>
        </div>

      </div>
    </div>
  );
};

