import { Video, PerformanceTier } from '../types';

const API_KEY = 'AIzaSyBZfTg06fuKvIv8nCBFBBCfKVvNjJxVif8';
const BASE_URL = 'https://www.googleapis.com/youtube/v3';

export const getChannelIdByHandle = async (handle: string): Promise<string | null> => {
  const cleanHandle = handle.startsWith('@') ? handle : `@${handle}`;
  try {
    const response = await fetch(`${BASE_URL}/search?part=snippet&type=channel&q=${encodeURIComponent(cleanHandle)}&key=${API_KEY}`);
    const data = await response.json();
    return data.items?.[0]?.id?.channelId || null;
  } catch (error) {
    console.error('Error fetching channel ID:', error);
    return null;
  }
};

export const getChannelStats = async (channelId: string) => {
  try {
    const response = await fetch(`${BASE_URL}/channels?part=statistics,contentDetails,snippet&id=${channelId}&key=${API_KEY}`);
    const data = await response.json();
    const channel = data.items?.[0];
    return {
      uploadsPlaylistId: channel?.contentDetails?.relatedPlaylists?.uploads,
      avgViews: parseInt(channel?.statistics?.viewCount) / parseInt(channel?.statistics?.videoCount) || 10000,
      title: channel?.snippet?.title,
      thumbnail: channel?.snippet?.thumbnails?.default?.url
    };
  } catch (error) {
    console.error('Error fetching channel stats:', error);
    return null;
  }
};

export const getLatestVideos = async (uploadsPlaylistId: string, limit = 5): Promise<Video[]> => {
  try {
    const response = await fetch(`${BASE_URL}/playlistItems?part=snippet,contentDetails&playlistId=${uploadsPlaylistId}&maxResults=${limit}&key=${API_KEY}`);
    const data = await response.json();
    const videoIds = data.items.map((item: any) => item.contentDetails.videoId).join(',');

    const statsResponse = await fetch(`${BASE_URL}/videos?part=statistics,contentDetails,snippet&id=${videoIds}&key=${API_KEY}`);
    const statsData = await statsResponse.json();

    // In a real scenario, we'd calculate baseline views from a larger sample
    // For this demo, we'll use a fixed baseline for HoggoYT context or from stats
    const baseline = 15000; 

    return statsData.items.map((v: any): Video => {
      const views = parseInt(v.statistics.viewCount);
      const outlierScore = parseFloat((views / baseline).toFixed(2));

      let tier: PerformanceTier = 'Average';
      if (outlierScore >= 3) tier = 'Elite';
      else if (outlierScore >= 1.5) tier = 'Strong';
      else if (outlierScore < 0.5) tier = 'Weak';

      return {
        video_id: v.id,
        title: v.snippet.title,
        thumbnail_url: v.snippet.thumbnails.maxres?.url || v.snippet.thumbnails.high?.url,
        published_at: new Date(v.snippet.publishedAt).toLocaleDateString(),
        views: views,
        likes: parseInt(v.statistics.likeCount),
        comments_count: parseInt(v.statistics.commentCount),
        ctr: 12.5, // CTR isn't available via public API
        avg_view_duration: '08:45', // AVD isn't available via public API
        outlier_score: outlierScore,
        performance_tier: tier
      };
    });
  } catch (error) {
    console.error('Error fetching videos:', error);
    return [];
  }
};

export const getVideoDetails = async (url: string) => {
  const videoId = url.split('v=')[1]?.split('&')[0] || url.split('/').pop();
  if (!videoId) return null;

  try {
    const response = await fetch(`${BASE_URL}/videos?part=snippet,statistics&id=${videoId}&key=${API_KEY}`);
    const data = await response.json();
    const v = data.items?.[0];
    if (!v) return null;

    return {
      title: v.snippet.title,
      thumbnail_url: v.snippet.thumbnails.maxres?.url || v.snippet.thumbnails.high?.url,
      views: parseInt(v.statistics.viewCount),
      videoId: v.id
    };
  } catch (error) {
    console.error('Error fetching video details:', error);
    return null;
  }
};

