            </div>
        </div>
        <button 
          onClick={handleReset}
          className="px-3 py-1.5 border border-gray-200 rounded-lg text-xs font-semibold text-gray-600 hover:bg-white transition-colors"
        >
            Reset Context
        </button>
      </div>

      {/* Chat Area */}
      <div className="flex-1 p-6 space-y-6 overflow-y-auto">
        {messages.map((msg, i) => (
          <div key={i} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'max-w-3xl'}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 mt-1 ${
              msg.role === 'model' ? 'bg-gray-800 text-white' : 'bg-emerald-100 text-emerald-700'
            }`}>
              {msg.role === 'model' ? <Sparkles size={14} /> : <div className="text-[10px] font-bold">ME</div>}
            </div>
            <div className={`p-4 rounded-2xl text-sm leading-relaxed border ${
              msg.role === 'model' 
                ? 'bg-gray-50 rounded-tl-none text-gray-700 border-gray-100' 
                : 'bg-emerald-800 text-white border-emerald-900 rounded-tr-none'
