import { SidebarItem } from './components/SidebarItem';
import { AddIdeaModal } from './components/AddIdeaModal';
import { INITIAL_IDEAS } from './constants';
import { Idea, Video } from './types';
import { getChannelIdByHandle, getChannelStats, getAllVideos } from './services/youtubeService';

type View = 'dashboard' | 'outliers' | 'competitors' | 'ideas' | 'sparring' | 'settings';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isAddIdeaModalOpen, setIsAddIdeaModalOpen] = useState(false);
  const [ideas, setIdeas] = useState<Idea[]>(INITIAL_IDEAS);

  const [channelData, setChannelData] = useState<any>(null);
  const [myVideos, setMyVideos] = useState<Video[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Initial Fetch for HoggoYT
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      const handle = localStorage.getItem('growiq_channel_handle') || '@HoggoYT';
      const channelId = await getChannelIdByHandle(handle);
      if (channelId) {
        const stats = await getChannelStats(channelId);
        if (stats) {
          setChannelData(stats);
          // Fetch ALL videos instead of just latest 5
          const videos = await getAllVideos(stats.uploadsPlaylistId);
          setMyVideos(videos);
        }
      }
      setIsLoading(false);
    };
    loadData();
  }, []);

  const handleSaveIdea = (newIdea: Idea) => {
    setIdeas(prev => [newIdea, ...prev]);
  };

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-full flex flex-col items-center justify-center text-gray-400">
          <Loader2 size={48} className="animate-spin mb-4 text-emerald-600" />
          <p className="font-medium">Fetching Channel Intelligence...</p>
          <p className="text-xs mt-2 opacity-60 italic">Pulling all video data & calculating outliers...</p>
        </div>
      );
    }

    switch (currentView) {
      case 'dashboard':
        return <DashboardHome dynamicVideos={myVideos} onChangeView={setCurrentView} onOpenAddIdea={() => setIsAddIdeaModalOpen(true)} />;
      case 'outliers':
        return <OutlierExplorer />;
      case 'competitors':
        return <Competitors />;
      case 'ideas':
        return <IdeaQueue ideas={ideas} onOpenAddIdea={() => setIsAddIdeaModalOpen(true)} />;
      case 'sparring':
        return <SparringPartner />;
      case 'settings':
        return <Settings />;
      default:
        return <DashboardHome dynamicVideos={myVideos} onChangeView={setCurrentView} onOpenAddIdea={() => setIsAddIdeaModalOpen(true)} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#F4F7F6]">
      <AddIdeaModal 
        isOpen={isAddIdeaModalOpen} 
        onClose={() => setIsAddIdeaModalOpen(false)}
        onSave={handleSaveIdea}
      />

      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      <aside className={`fixed lg:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-100 transition-transform duration-300 ease-in-out flex flex-col ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}`}>
        <div className="flex flex-col h-full">
          <div className="px-6 py-8">
            <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-emerald-800 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-900/10">
                    <TrendingUp className="text-white w-6 h-6" />
                </div>
                <div>
                    <h1 className="text-xl font-extrabold text-gray-900 leading-none tracking-tight">Growth</h1>
                    <span className="text-[10px] font-bold text-gray-400 tracking-[0.2em] uppercase">Intelligence</span>
                </div>
            </div>
          </div>

          <div className="flex-1 px-4 overflow-y-auto">
            <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-2">Menu</div>
            <nav className="space-y-1">
                <SidebarItem icon={<LayoutDashboard size={20} />} label="Dashboard" isActive={currentView === 'dashboard'} onClick={() => { setCurrentView('dashboard'); setIsMobileMenuOpen(false); }} />
                <SidebarItem icon={<TrendingUp size={20} />} label="Outlier Explorer" isActive={currentView === 'outliers'} onClick={() => { setCurrentView('outliers'); setIsMobileMenuOpen(false); }} />
                <SidebarItem icon={<Users size={20} />} label="Competitors" isActive={currentView === 'competitors'} onClick={() => { setCurrentView('competitors'); setIsMobileMenuOpen(false); }} />
                <SidebarItem icon={<Lightbulb size={20} />} label="Idea Queue" isActive={currentView === 'ideas'} count={ideas.length} onClick={() => { setCurrentView('ideas'); setIsMobileMenuOpen(false); }} />
                <SidebarItem icon={<MessageSquare size={20} />} label="Sparring Partner" isActive={currentView === 'sparring'} onClick={() => { setCurrentView('sparring'); setIsMobileMenuOpen(false); }} />
            </nav>

            <div className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-8">General</div>
            <nav className="space-y-1">
                <SidebarItem icon={<SettingsIcon size={20} />} label="Settings" isActive={currentView === 'settings'} onClick={() => { setCurrentView('settings'); setIsMobileMenuOpen(false); }} />
                <SidebarItem icon={<LogOut size={20} />} label="Logout" isActive={false} onClick={() => {}} />
            </nav>
          </div>

          <div className="p-4 border-t border-gray-100">
            <div className="flex items-center gap-3 px-2 py-2 rounded-xl hover:bg-gray-50 transition-colors cursor-pointer">
              {channelData?.thumbnail ? (
                <img src={channelData.thumbnail} className="w-9 h-9 rounded-full object-cover" />
              ) : (
                <div className="w-9 h-9 bg-teal-800 rounded-full flex items-center justify-center text-white font-bold text-sm">US</div>
              )}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-bold text-gray-900 truncate">{channelData?.title || 'User'}</p>
                <p className="text-xs text-gray-500 truncate">@{localStorage.getItem('growiq_channel_handle')?.replace('@', '') || 'YourChannel'}</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full w-full overflow-hidden bg-white/50">
        <header className="h-20 flex items-center justify-between px-8 bg-transparent shrink-0">
          <div className="flex items-center gap-4 lg:hidden">
            <button onClick={toggleMobileMenu} className="p-2 bg-white rounded-xl shadow-sm text-gray-600"><Menu size={20} /></button>
            <span className="font-bold text-gray-800">Growth Intelligence</span>
          </div>

          <div className="hidden lg:flex items-center flex-1 max-w-xl">
             <div className="relative w-full group">
                <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-600 transition-colors" />
                <input type="text" placeholder="Search task, outliers, or ideas..." className="w-full bg-white border border-gray-200 rounded-xl py-2.5 pl-10 pr-4 text-sm outline-none focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 transition-all shadow-sm" />
            </div>
          </div>

          <div className="flex items-center gap-6 ml-auto">
             <div className="hidden md:flex flex-col items-end">
                <span className="text-[10px] font-bold text-gray-400 uppercase">Status</span>
                <span className="text-xs font-bold text-emerald-600 flex items-center gap-1">
                  <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div> Connected
                </span>
             </div>
             <button className="p-2 bg-white rounded-full text-gray-400 hover:text-emerald-600 hover:bg-emerald-50 transition-colors border border-transparent hover:border-emerald-100"><Bell size={18} /></button>
             <div className="w-8 h-8 rounded-full bg-emerald-800 flex items-center justify-center text-white text-xs font-bold shadow-md shadow-emerald-200">HO</div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto px-4 md:px-8 pb-8">
            {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;
